class Solution:
    def preimageSizeFZF(self, k: int) -> int:
        def f(x):
            s = 0
            while x:
                x //= 5; s += x
            return s
        if k == 0: return 0
        lo, hi = 0, 5 * (k + 1)
        while lo < hi:
            mid = (lo + hi) // 2
            if f(mid) < k: lo = mid + 1
            else: hi = mid
        if f(lo) != k: return 0
        return 5

