class Solution {
public:
    int preimageSizeFZF(int k) {
        auto f=[](long long x){ int s=0; while(x){ x/=5; s+=x; } return s; };
        if(k==0) return 0;
        long long lo=0, hi=5LL*(k+1);
        while(lo<hi){ long long mid=(lo+hi)/2; if(f(mid)<k) lo=mid+1; else hi=mid; }
        if(f(lo)!=k) return 0;
        return 5;
    }
};

